mapper.select:
SELECT movie_id
FROM stats_hot_movies
WHERE period_type = #{period}
  AND calc_date = (SELECT MAX(calc_date) FROM stats_hot_movies WHERE period_type = #{period})
ORDER BY hot_score DESC
LIMIT #{limit}

SELECT similar_movie_id AS similarMovieId,
       similarity_score AS similarityScore,
       similarity_type  AS similarityType
FROM stats_similar_movies
WHERE movie_id = #{movieId}

    AND similarity_type = #{similarityType}

ORDER BY similarity_score DESC
LIMIT #{limit}
